import React, { useState } from 'react';

const quizData = [
  { question: "What is my favorite burger stall?", options: ["Angels Burger", "Out Box", "Franks", "Minute Burger"], answer: 2 },
  { question: "What is my favorite pet?", options: ["Cat", "Bird", "Snake", "Penguin"], answer: 3 },
  { question: "What is my former position in CCS student body organization?", options: ["Vice Mayor", "Peace Officer", "P.I.O", "Muse"], answer: 0 },
  { question: "What is my favorite color", options: ["Black", "Gray", "Green", "Pink"], answer: 3 },
  { question: "What is my favorite instant noodles", options: ["Lucky Me Pancit canton", "Yakisoba", "Mie Goreng", "Buldak"], answer: 2 },
  { question: "What is my usual ordered coffee", options: ["Americano", "Matcha", "Mocha", "Spanish Latte"], answer: 2 },
  { question: "How many cats do i have", options: ["3", "7", "5", "8"], answer: 1 },
  { question: "Kanino ako pinakamatagal nag move on?", options: ["Harisson", "Dwight", "Mackie", "Lester"], answer: 2 }
];

function AboutPage() {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selectedIdx, setSelectedIdx] = useState(null);
  const [score, setScore] = useState(0);
  const [result, setResult] = useState({ text: '', color: '' });
  const [quizFinished, setQuizFinished] = useState(false);

  const handleSelect = (index) => {
    if (result.text) return; // Prevent changing answer after submission
    setSelectedIdx(index);
  };

  const handleSubmit = () => {
    const currentData = quizData[currentIdx];
    if (selectedIdx === currentData.answer) {
      setScore(score + 1);
      setResult({ text: 'Correct!', color: 'green' });
    } else {
      setResult({ text: `Wrong! Correct answer: ${currentData.options[currentData.answer]}`, color: 'red' });
    }

    setTimeout(() => {
      if (currentIdx + 1 < quizData.length) {
        setCurrentIdx(currentIdx + 1);
        setSelectedIdx(null);
        setResult({ text: '', color: '' });
      } else {
        setQuizFinished(true);
      }
    }, 1500);
  };

  return (
    <main>
      {/* Gallery Section 1 */}
      <section className="hero">
        <h1>The Keeper of the Personal Gallery</h1>
        <p>I use the lens as a mirror to catch the light I often forget I carry...</p>
      </section>
      <section className="preview-grid">
        {["ed6", "ed7", "ed8", "ed9", "ed10"].map(img => (
          <div className="card" key={img}><img src={`/photos/${img}.png.jpg`} width="175" height="175" alt="Gallery" /></div>
        ))}
      </section>

      {/* Gallery Section 2 */}
      <section className="preview-grid">
        {["ed18", "ed19", "ed20", "ed21", "ed22"].map(img => (
          <div className="card" key={img}><img src={`/photos/${img}.png.jpg`} width="175" height="175" alt="Gallery" /></div>
        ))}
      </section>

      <section className="hero">
        <h1>The Curator of Collective Growth</h1>
        <p>Leadership has been my compass, pointing me toward a version of myself I didn’t know existed...</p>
      </section>

      {/* Gallery Section 3 */}
      <section className="preview-grid">
        {["ed11", "ed12", "ed2", "ed13", "ed14"].map(img => (
          <div className="card" key={img}><img src={`/photos/${img}.png.jpg`} width="175" height="175" alt="Gallery" /></div>
        ))}
      </section>

      {/* Quiz Section */}
      <section className="quiz-section">
        <div className="quiz-container">
          {!quizFinished ? (
            <>
              <h2>{quizData[currentIdx].question}</h2>
              <div className="options">
                {quizData[currentIdx].options.map((option, index) => (
                  <div 
                    key={index} 
                    className={`option ${selectedIdx === index ? 'selected' : ''}`}
                    onClick={() => handleSelect(index)}
                  >
                    {option}
                  </div>
                ))}
              </div>
              <button onClick={handleSubmit} disabled={selectedIdx === null || result.text}>
                Submit Answer
              </button>
              <div style={{ color: result.color, marginTop: '10px', fontWeight: 'bold' }}>{result.text}</div>
            </>
          ) : (
            <div>
              <h2>Quiz Complete!</h2>
              <div style={{ fontWeight: 'bold' }}>Your final score is {score} out of {quizData.length}.</div>
            </div>
          )}
        </div>
      </section>

      <footer>
        <p>&copy; Cead. All rights reserved. | Contact: edrickbillones0@gmail.com</p>
      </footer>
    </main>
  );
}

export default AboutPage;
